@push('js')<script>document.addEventListener('DOMContentLoaded',()=>{const space=document.getElementById('venue_space_id'),start=document.getElementById('start_time'),end=document.getElementById('end_time'),total=document.getElementById('calculated_total'),paid=document.getElementById('paid_amount'),remaining=document.getElementById('remaining_amount'),method=document.getElementById('payment_method'),otherWrap=document.getElementById('other_method_wrap'),other=document.getElementById('payment_method_other');function calc(){const price=parseFloat(space.options[space.selectedIndex]?.dataset.price||0),s=start.value,e=end.value;if(!s||!e){return}let sm=parseInt(s.split(':')[0])*60+parseInt(s.split(':')[1]),em=parseInt(e.split(':')[0])*60+parseInt(e.split(':')[1]);if(em<=sm)em+=1440;const amount=((em-sm)/60)*price;total.value=amount.toFixed(2);remaining.value=Math.max(0,amount-parseFloat(paid.value||0)).toFixed(2);paid.setCustomValidity(parseFloat(paid.value||0)>amount?'{{ trans('admin.bookings.paid_amount_exceeds_total') }}':'')}function toggleOther(){const show=method.value==='other';otherWrap.classList.toggle('d-none',!show);other.required=show}[space,start,end,paid].forEach(el=>el.addEventListener('input',calc));method.addEventListener('change',toggleOther);calc();toggleOther()});</script>@endpush
